Section: Build a Support Desk -> Start With an In-Memory Adapter
Content: function App() {
  const [view, setView] = useState<View>('customer');
  const [chatKey, setChatKey] = useState(0);
  const [adapter] = useState(() =>
    createInMemorySupportFlowAdapter({
      nextTicketNumber: 3001,
    })
  );

  const flow =
    view === 'customer'
      ? createSupportUserFlow({
          adapter,
          customer: CUSTOMER,
          brandName: 'Harbor Support',
        })
      : createSupportAdminFlow({
          adapter,
          agent: AGENT,
          brandName: 'Harbor Ops',
        });

  function switchView(nextView: View): void {
    if (nextView === view) {
      return;
    }

    resetChatWorkspace();
    setView(nextView);
    setChatKey(current => current + 1);
  }

  return (
    <>
      <button
        type='button'
        onClick={() => {
          switchView('customer');
        }}
      >
        Customer
      </button>
      <button
        type='button'
        onClick={() => {
          switchView('admin');
        }}
      >
        Admin
      </button>

      <Chat
        key={`${view}-${chatKey}`}
        initialMessages={flow.initialMessages}
      />
    </>
  );
}
```

