Section: Connect to an LLM Backend -> Backend Route Example
Content: ```ts
import type { LLMMessage } from 'react-actions-chat-llms';

interface GenerateTextRequestBody {
  readonly messages: readonly LLMMessage[];
  readonly maxOutputTokens?: number | undefined;
}

interface OpenAIResponsesResponse {
  readonly output_text?: string;
  readonly error?: {
    readonly message?: string;
  };
}

export async function POST(request: Request): Promise<Response> {
  const body = (await request.json()) as GenerateTextRequestBody;

  const response = await fetch('https://api.openai.com/v1/responses', {
    method: 'POST',
    headers: {
      Authorization: `Bearer ${process.env.OPENAI_API_KEY ?? ''}`,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify({
      model: 'gpt-5-mini',
      input: body.messages,
      ...(body.maxOutputTokens
        ? {
            max_output_tokens: body.maxOutputTokens,
          }
        : {}),
    }),
  });

  const data = (await response.json()) as OpenAIResponsesResponse;

  if (!response.ok) {
    return Response.json(
      {
        message:
          data.error?.message ??
          `OpenAI request failed with status ${response.status}.`,
      },
      { status: response.status }
    );
  }

  return Response.json({
    text: data.output_text ?? '',
  });
}
```

